const tag = 'zzc' + String(Date.now()).slice(-6);
const customerChat = '91' + String(Date.now() + 11111).slice(-10);
const cancelChat = '91' + String(Date.now() + 22222).slice(-10);
return [{
  json: {
    tag,
    owner_chat_id: '919148969183',
    customer_chat_id: customerChat,
    cancel_chat_id: cancelChat,
    empty_chat_id: '91' + String(Date.now() + 33333).slice(-10),
    product_name: tag + ' user item',
    product_message: tag + ' user item 45 10',
    address: '221 Test Street, Bengaluru',
    test_mode: true,
  },
}];

const seed = $('Seed Customer Inputs').first().json || {};
const ownerPreview = $('Run Owner Item Preview').first().json || {};
const ownerApply = $('Run Owner Item Confirm').first().json || {};
const emptyPlace = $('Run Empty Place Order').first().json || {};
const emptyConfirm = $('Run Empty Confirm Order').first().json || {};
const add = $('Run Customer Add').first().json || {};
const view = $('Run View Cart').first().json || {};
const place = $('Run Customer Place').first().json || {};
const confirm = $('Run Customer Confirm').first().json || {};
const track = $('Run Track Order').first().json || {};
const cancel = $('Run Cancel Order').first().json || {};
const dbRows = $('Verify Customer DB State').all().map((item) => item.json || {});
const byKind = (kind) => dbRows.find((row) => row.kind === kind) || {};
const hasConfirmButton = Array.isArray(place.buttons) && place.buttons.some((button) => String(button.id || '') === 'confirm_order');
return [{
  json: {
    customer_chat_id: seed.customer_chat_id,
    cancel_chat_id: seed.cancel_chat_id,
    responses: {
      owner_preview: String(ownerPreview.body_text || ownerPreview.confirmation_message || ''),
      owner_apply: String(ownerApply.body_text || ownerApply.confirmation_message || ''),
      empty_place: String(emptyPlace.body_text || emptyPlace.confirmation_message || ''),
      empty_confirm: String(emptyConfirm.body_text || emptyConfirm.confirmation_message || ''),
      add: String(add.confirmation_message || add.body_text || ''),
      view: String(view.confirmation_message || view.body_text || ''),
      place: String(place.body_text || place.confirmation_message || ''),
      confirm: String(confirm.confirmation_message || confirm.body_text || ''),
      track: String(track.confirmation_message || track.body_text || ''),
      cancel: String(cancel.confirmation_message || cancel.body_text || ''),
    },
    checks: {
      owner_preview_has_confirm: Array.isArray(ownerPreview.buttons) && ownerPreview.buttons.some((button) => String(button.id || '').startsWith('owner_inv_confirm__')),
      owner_apply_ok: /catalog updated/i.test(String(ownerApply.body_text || ownerApply.confirmation_message || '')),
      empty_place_ok: /cart is empty/i.test(String(emptyPlace.body_text || emptyPlace.confirmation_message || '')),
      empty_confirm_ok: /no pending order|no pending bill|there is no pending/i.test(String(emptyConfirm.confirmation_message || emptyConfirm.body_text || '')),
      add_ok: /added|cart|₹|rs\.?/i.test(String(add.confirmation_message || add.body_text || '')),
      view_ok: /cart|total/i.test(String(view.confirmation_message || view.body_text || '')),
      place_has_confirm: hasConfirmButton,
      confirm_ok: /order confirmed/i.test(String(confirm.confirmation_message || confirm.body_text || '')),
      track_ok: /order|status|confirmed|processing/i.test(String(track.confirmation_message || track.body_text || '')),
      cancel_ok: /cancel/i.test(String(cancel.confirmation_message || cancel.body_text || '')),
      db_order_summary_present: Number(byKind('order_summary').value || 0) >= 1,
      db_orders_present: Number(byKind('orders').value || 0) >= 1,
      cancel_pending_cleared: Number(byKind('cancel_pending').value || 0) === 0,
      customer_active_cart_cleared: Number(byKind('active_cart_customer').value || 0) === 0,
      cancel_active_cart_cleared: Number(byKind('active_cart_cancel').value || 0) === 0,
      inventory_rows_created: Number(byKind('inventory_rows').value || 0) >= 1,
    },
    db_rows: dbRows,
  },
}];
